# Generated By: Claude Code (Claude Opus 4.6)
"""Fetch and persist Claude Code usage limits from the Anthropic OAuth API.

Each successful fetch inserts a new row into claude_limits, building
historical data. The TTL is checked against the most recent row's
fetched_at timestamp. Responses include refresh_after — the timestamp
when the next fetch will be attempted (accounts for backoff on failure).

Completely inert when disabled via config (fetch_limits=false).
"""

import json
import logging
import time
import urllib.request

import aiosqlite

from agentpulse import config
from agentpulse.platforms.claude import schema

logger = logging.getLogger(__name__)

_API_URL = "https://api.anthropic.com/api/oauth/usage"
_CREDENTIALS_PATH = config.CLAUDE_HOME / ".credentials.json"
_TTL_SECONDS = 120
_MAX_BACKOFF_SECONDS = 3600

_last_attempt_at: float = 0.0
_consecutive_failures: int = 0
_cached_limits: dict | None = None
_cached_limits_fetched_at: float = 0.0


def _read_token() -> str | None:
    """Read the OAuth access token from Claude credentials."""
    try:
        data = json.loads(_CREDENTIALS_PATH.read_text(encoding="utf-8"))
        token: str | None = data.get("claudeAiOauth", {}).get("accessToken")
        return token
    except (json.JSONDecodeError, OSError, KeyError):
        return None


def _fetch_from_api(*, token: str) -> dict | None:
    """Fetch usage data from the Anthropic OAuth API."""
    try:
        req = urllib.request.Request(
            _API_URL,
            headers={
                "Authorization": f"Bearer {token}",
                "anthropic-beta": "oauth-2025-04-20",
            },
        )
        resp = urllib.request.urlopen(req, timeout=10)
        data = json.loads(resp.read())
        if isinstance(data, dict):
            return data
    except Exception as exc:
        logger.warning("limits API fetch failed: %s", exc)
    return None


def _backoff_seconds() -> float:
    """Calculate backoff duration based on consecutive failures."""
    if _consecutive_failures == 0:
        return 0.0
    return float(
        min(
            (2**_consecutive_failures) * _TTL_SECONDS,
            _MAX_BACKOFF_SECONDS,
        )
    )


def _next_refresh_at() -> float:
    """Calculate when the next fetch will be attempted."""
    if _consecutive_failures == 0:
        # Normal TTL from last successful fetch
        return _cached_limits_fetched_at + _TTL_SECONDS
    # In backoff — next attempt is last_attempt + cooldown
    return _last_attempt_at + _backoff_seconds()


def _format_row(row: dict, *, now: float) -> dict:
    """Format a claude_limits DB row into the API response shape."""
    raw = json.loads(row["raw_response"])
    fetched_at = row["fetched_at"]
    age = now - fetched_at

    result: dict = {
        "available": True,
        "fetched_at": fetched_at,
        "age_seconds": age,
        "stale": age > _TTL_SECONDS,
        "refresh_after": _next_refresh_at(),
    }

    for key in (
        "five_hour",
        "seven_day",
        "seven_day_opus",
        "seven_day_sonnet",
    ):
        bucket = raw.get(key)
        if bucket and isinstance(bucket, dict):
            result[key] = {
                "utilization": bucket.get("utilization"),
                "resets_at": bucket.get("resets_at"),
            }

    extra = raw.get("extra_usage")
    if extra and isinstance(extra, dict):
        result["extra_usage"] = {
            "is_enabled": extra.get("is_enabled", False),
            "monthly_limit_usd": (
                extra["monthly_limit"] / 100
                if extra.get("monthly_limit") is not None
                else None
            ),
            "used_credits_usd": (
                extra["used_credits"] / 100
                if extra.get("used_credits") is not None
                else None
            ),
            "utilization": extra.get("utilization"),
        }

    return result


async def get_limits(db: aiosqlite.Connection) -> dict | None:
    """Get current usage limits, fetching from API if stale.

    Check order: in-memory cache → DB → API fetch → insert new row.
    Returns None if no token and no historical data.
    """
    global _last_attempt_at, _consecutive_failures
    global _cached_limits, _cached_limits_fetched_at

    now = time.time()

    # In-memory cache — skip DB if before next refresh
    if _cached_limits is not None and now < _next_refresh_at():
        _cached_limits["age_seconds"] = now - _cached_limits_fetched_at
        return _cached_limits

    # DB — check most recent row
    latest = await schema.get_latest_limits(db)
    if latest is not None:
        age = now - latest["fetched_at"]
        if age < _TTL_SECONDS:
            _cached_limits_fetched_at = latest["fetched_at"]
            result = _format_row(latest, now=now)
            _cached_limits = result
            return result

    # Backoff check
    if _consecutive_failures > 0:
        cooldown = _backoff_seconds()
        if (now - _last_attempt_at) < cooldown:
            logger.debug(
                "limits fetch in backoff failures=%d cooldown=%.0fs",
                _consecutive_failures,
                cooldown,
            )
            if latest is not None:
                return _format_row(latest, now=now)
            return None

    # Fetch from API
    token = _read_token()
    if token is None:
        logger.debug("no OAuth token found, limits disabled")
        if latest is not None:
            return _format_row(latest, now=now)
        return None

    _last_attempt_at = now
    raw = _fetch_from_api(token=token)

    if raw is not None:
        fetched_at = time.time()
        await schema.insert_limits(
            db,
            fetched_at=fetched_at,
            raw_response=json.dumps(raw),
        )
        _consecutive_failures = 0
        _cached_limits_fetched_at = fetched_at
        logger.info("limits fetched and stored")
        new_row = await schema.get_latest_limits(db)
        if new_row is not None:
            result = _format_row(new_row, now=fetched_at)
            _cached_limits = result
            return result

    _consecutive_failures += 1
    logger.warning(
        "limits fetch failed attempts=%d backoff=%.0fs",
        _consecutive_failures,
        _backoff_seconds(),
    )

    if latest is not None:
        return _format_row(latest, now=now)
    return None


def reset_state() -> None:
    """Reset backoff and cache state (for testing)."""
    global _last_attempt_at, _consecutive_failures
    global _cached_limits, _cached_limits_fetched_at
    _last_attempt_at = 0.0
    _consecutive_failures = 0
    _cached_limits = None
    _cached_limits_fetched_at = 0.0
